const currentTemp = parseFloat(msg.payload);
const targetTemp = parseFloat(global.get('homeassistant.homeAssistant.states["input_number.mh1_target_temp"].state'));
const manualOverride = global.get('homeassistant.homeAssistant.states["input_boolean.mh1_manual_override"].state') === 'on';
const radiatorState = global.get('homeassistant.homeAssistant.states["switch.mh1"].state');

// Get adjustable parameters
const outsideTempThreshold = parseFloat(global.get('homeassistant.homeAssistant.states["input_number.mh1_outside_temp_threshold"].state')) || 10;
const minRoomTemp = parseFloat(global.get('homeassistant.homeAssistant.states["input_number.mh1_min_room_temp"].state')) || 19;
const maxRoomTemp = parseFloat(global.get('homeassistant.homeAssistant.states["input_number.mh1_max_room_temp"].state')) || 21;
const outsideTemp = parseFloat(global.get('homeassistant.homeAssistant.states["sensor.outside_temperature"].state'));

// Get configurable schedule times from input_datetime helpers
const startTimeStr = global.get('homeassistant.homeAssistant.states["input_datetime.mh1_start_time"].state') || "22:00:00";
const endTimeStr = global.get('homeassistant.homeAssistant.states["input_datetime.mh1_end_time"].state') || "07:00:00";

// Parse schedule times (format: "HH:MM:SS")
const startHour = parseInt(startTimeStr.split(':')[0]);
const endHour = parseInt(endTimeStr.split(':')[0]);

// Get current time
const now = new Date();
const currentHour = now.getHours();
const currentMinute = now.getMinutes();

// Check if within STRICT schedule (supports overnight ranges)
const withinSchedule = startHour > endHour 
    ? (currentHour >= startHour || currentHour < endHour)  // Overnight: 22:00-07:00
    : (currentHour >= startHour && currentHour < endHour); // Same day: 08:00-16:00

// Decision logic - STRICT SCHEDULE ENFORCEMENT
let shouldHeat = false;
let reason = '';

// CRITICAL: Check schedule FIRST (unless manual override)
if (manualOverride) {
    // Manual override bypasses all other checks
    shouldHeat = currentTemp < targetTemp;
    reason = shouldHeat ? 'Manual override - heating' : 'Manual override - target reached';
} else if (!withinSchedule) {
    // ALWAYS OFF outside configured schedule window
    shouldHeat = false;
    reason = `Outside schedule (${currentHour}:${String(currentMinute).padStart(2,'0')} not in ${startTimeStr.substring(0,5)}-${endTimeStr.substring(0,5)})`;
} else if (outsideTemp >= outsideTempThreshold) {
    // Within schedule but outside temp too warm
    shouldHeat = false;
    reason = `Outside ${outsideTemp}°C ≥ ${outsideTempThreshold}°C - no heating needed`;
} else if (currentTemp >= maxRoomTemp) {
    // Within schedule but room too warm
    shouldHeat = false;
    reason = `Room ${currentTemp}°C ≥ max ${maxRoomTemp}°C`;
} else if (currentTemp < minRoomTemp) {
    // Within schedule and below minimum - heat
    shouldHeat = true;
    reason = `Room ${currentTemp}°C < min ${minRoomTemp}°C`;
} else if (currentTemp < (targetTemp - 0.5)) {
    // Within schedule and below target (with hysteresis)
    shouldHeat = true;
    reason = `Temp ${currentTemp}°C < target ${targetTemp}°C`;
} else if (currentTemp >= targetTemp) {
    // Within schedule but at or above target
    shouldHeat = false;
    reason = `Temp ${currentTemp}°C ≥ target ${targetTemp}°C`;
} else {
    // Within hysteresis band - maintain current state
    shouldHeat = radiatorState === 'on';
    reason = 'Within hysteresis band';
}

// Store state for status
flow.set('mh1_should_heat', shouldHeat);
flow.set('mh1_reason', reason);

msg.shouldHeat = shouldHeat;
msg.currentState = radiatorState;
msg.reason = reason;

node.status({
    fill: shouldHeat ? 'green' : 'grey',
    shape: 'dot',
    text: `${currentTemp}°C | ${reason} | ${withinSchedule ? 'IN' : 'OUT'} schedule`
});

return msg;

