    // Kids home - heat to target with 0.5°C hysteresis
    shouldHeat = true;
    reason = `Kids home - ${currentTemp}°C < target ${targetTemp}°C`;
} else if (currentTemp >= targetTemp) {
    shouldHeat = false;
